import { FC } from 'react';
import { InjectedComponent, useBook, useSelector } from '@topwrite/common';
import { Helmet, HelmetProvider } from 'react-helmet-async';
import useTitle from '@/lib/use-title';

const Main: FC = () => {

    const { summary } = useBook();
    const file = useSelector('file');

    const article = summary.getArticle(article => article.getPath() === file.path);

    const title = useTitle();

    return <HelmetProvider>
        <Helmet>
            <title>{`${article ? `${article.title} - ` : ''}${title}`}</title>
        </Helmet>
        <InjectedComponent matching={{ role: 'app' }} />
    </HelmetProvider>;
};

export default Main;
